  1→/**
  2→ * 飞书消息监听器 - 简化版
  3→ *
  4→ * 监听飞书消息并注入到本地 Claude Code CLI
  5→ */
  6→
  7→const fs = require('fs');
  8→const path = require('path');
  9→const { spawn } = require('child_process');
 10→
 11→const CONFIG_FILE = path.join(__dirname, 'feishu-config.json');
 12→const MESSAGE_QUEUE = path.join(__dirname, '.feishu_queue.json');
 13→
 14→class FeishuListener {
 15→  constructor() {
 16→    this.isRunning = false;
 17→    this.terminalProcess = null;
 18→  }
 19→
 20→  start() {
 21→    this.isRunning = true;
 22→    console.log('🎯 飞书消息监听器已启动');
 23→    console.log('📡 等待飞书消息...\n');
 24→
 25→    // 监控消息队列
 26→    this.watchMessageQueue();
 27→  }
 28→
 29→  watchMessageQueue() {
 30→    // 每秒检查一次
 31→    setInterval(() => {
 32→      this.processMessages();
 33→    }, 1000);
 34→  }
 35→
 36→  processMessages() {
 37→    if (!fs.existsSync(MESSAGE_QUEUE)) {
 38→      return;
 39→    }
 40→
 41→    try {
 42→      const messages = JSON.parse(fs.readFileSync(MESSAGE_QUEUE, 'utf8'));
 43→
 44→      if (messages.length > 0) {
 45→        const message = messages.shift();
 46→        this.handleMessage(message);
 47→
 48→        // 更新队列
 49→        fs.writeFileSync(MESSAGE_QUEUE, JSON.stringify(messages, null, 2));
 50→      }
 51→    } catch (error) {
 52→      // 忽略错误
 53→    }
 54→  }
 55→
 56→  handleMessage(message) {
 57→    console.log('\n' + '='.repeat(50));
 58→    console.log('📨 收到飞书消息');
 59→    console.log('='.repeat(50));
 60→    console.log(`内容: ${message.text}`);
 61→    console.log('='.repeat(50) + '\n');
 62→
 63→    // 如果是命令，执行它
 64→    if (message.text.startsWith('/')) {
 65→      this.executeCommand(message.text);
 66→    } else {
 67→      // 作为输入注入到当前终端（需要配合其他工具）
 68→      this.sendNotification(`已收到: ${message.text}`);
 69→    }
 70→  }
 71→
 72→  executeCommand(command) {
 73→    console.log(`🔧 执行命令: ${command}\n`);
 74→
 75→    // 执行命令
 76→    const [cmd, ...args] = command.slice(1).split(' ');
 77→    const process = spawn(cmd, args, {
 78→      shell: true,
 79→      stdio: 'inherit'
 80→    });
 81→
 82→    process.on('close', (code) => {
 83→      this.sendNotification(`命令执行完成 (exit: ${code})`);
 84→    });
 85→  }
 86→
 87→  sendNotification(text) {
 88→    // 发送回飞书
 89→    console.log(`📤 发送通知: ${text}\n`);
 90→  }
 91→}
 92→
 93→// 启动监听器
 94→const listener = new FeishuListener();
 95→listener.start();
 96→
 97→// 优雅退出
 98→process.on('SIGINT', () => {
 99→  console.log('\n👋 飞书监听器已退出');
100→  process.exit(0);
101→});
