157→/**
158→ * 截断文本
159→ */
160→function truncateText(text, maxLength) {
161→  if (text.length <= maxLength) {
162→    return text;
163→  }
164→  return text.slice(0, maxLength) + '\n\n...(输出过长，已截断)';
165→}
