167→/**
168→ * 发送飞书消息（通过 clawdbot 飞书扩展）
169→ */
170→async function sendFeishuMessage(text, recipient = 'me') {
171→  // 这里可以调用 clawdbot 的飞书 API
172→  // 或者保存到文件由 clawdbot 读取
173→  log(`准备发送飞书消息给 ${recipient}: ${text.slice(0, 50)}...`, 'INFO');
174→
175→  // 临时方案：保存到文件
176→  const outbox = path.join(__dirname, '.feishu_outbox.json');
177→  let messages = [];
178→
179→  if (fs.existsSync(outbox)) {
180→    try {
181→      messages = JSON.parse(fs.readFileSync(outbox, 'utf8'));
182→    } catch (error) {
183→      messages = [];
184→    }
185→  }
186→
187→  messages.push({
188→    recipient: recipient,
189→    text: text,
190→    timestamp: new Date().toISOString()
191→  });
192→
193→  fs.writeFileSync(outbox, JSON.stringify(messages, null, 2));
194→
195→  return { success: true };
196→}
