198→/**
199→ * HTTP 请求处理
200→ */
201→async function handleRequest(req, res) {
202→  const url = req.url;
203→  const method = req.method;
204→
205→  log(`${method} ${url}`, 'INFO');
206→
207→  // CORS 头
208→  const corsHeaders = {
209→    'Access-Control-Allow-Origin': '*',
210→    'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
211→    'Access-Control-Allow-Headers': 'Content-Type, Authorization'
212→  };
213→
214→  // 处理 OPTIONS 预检请求
215→  if (method === 'OPTIONS') {
216→    res.writeHead(200, corsHeaders);
217→    res.end();
218→    return;
219→  }
220→
221→  // 路由处理
222→  if (url === '/health' || url === '/') {
223→    // 健康检查
224→    res.writeHead(200, { 'Content-Type': 'application/json', ...corsHeaders });
225→    res.end(JSON.stringify({
226→      status: 'ok',
227→      service: 'feishu-webhook-server',
228→      timestamp: new Date().toISOString()
229→    }));
230→    return;
231→  }
232→
233→  if (url === '/webhook/feishu' && method === 'POST') {
234→    // 飞书 webhook
235→    let body = '';
236→
237→    req.on('data', chunk => {
238→      body += chunk.toString();
239→    });
240→
241→    req.on('end', async () => {
242→      try {
243→        const payload = JSON.parse(body);
244→        log(`收到飞书 webhook: ${JSON.stringify(payload).slice(0, 200)}...`, 'INFO');
245→
246→        // 解析飞书消息
247→        // 飞书消息格式：https://open.feishu.cn/document/ukTMukTMukTM/uUTNz4SN1MjL1UzM
248→        let messageText = '';
249→        let sender = 'unknown';
250→
251→        if (payload.event) {
252→          const event = payload.event;
253→
254→          // 获取消息内容
255→          if (event.message && event.message.content) {
256→            const content = JSON.parse(event.message.content);
257→            messageText = content.text || '';
258→          }
259→
260→          // 获取发送者
261→          if (event.sender) {
262→            sender = event.sender.sender_id?.user_id || 'unknown';
263→          }
264→
265→          // 处理消息
266→          const result = await handleFeishuMessage(messageText, sender);
267→
268→          // 发送回复
269→          if (result.success && result.response) {
270→            await sendFeishuMessage(result.response, sender);
271→          }
272→
273→          // 返回成功（飞书需要 200 响应）
274→          res.writeHead(200, { 'Content-Type': 'application/json', ...corsHeaders });
275→          res.end(JSON.stringify({
276→            code: 0,
277→            msg: 'success'
278→          }));
279→
280→        } else {
281→          // 简单的消息格式（用于测试）
282→          messageText = payload.text || payload.message || '';
283→          const result = await handleFeishuMessage(messageText, payload.sender || 'test');
284→
285→          res.writeHead(200, { 'Content-Type': 'application/json', ...corsHeaders });
286→          res.end(JSON.stringify(result));
287→        }
288→
289→      } catch (error) {
290→        log(`处理 webhook 错误: ${error.message}`, 'ERROR');
291→        res.writeHead(500, { 'Content-Type': 'application/json', ...corsHeaders });
292→        res.end(JSON.stringify({
293→          error: error.message
294→        }));
295→      }
296→    });
297→
298→    return;
299→  }
300→
301→  if (url === '/api/command' && method === 'POST') {
302→    // 通用命令接口（用于测试）
303→    let body = '';
304→
305→    req.on('data', chunk => {
306→      body += chunk.toString();
307→    });
308→
309→    req.on('end', async () => {
310→      try {
311→        const payload = JSON.parse(body);
312→        const result = await handleFeishuMessage(payload.command || '', payload.sender || 'api');
313→
314→        res.writeHead(200, { 'Content-Type': 'application/json', ...corsHeaders });
315→        res.end(JSON.stringify(result));
316→
317→      } catch (error) {
318→        log(`API 错误: ${error.message}`, 'ERROR');
319→        res.writeHead(500, { 'Content-Type': 'application/json', ...corsHeaders });
320→        res.end(JSON.stringify({
321→          error: error.message
322→        }));
323→      }
324→    });
325→
326→    return;
327→  }
328→
329→  // 404
330→  res.writeHead(404, { 'Content-Type': 'application/json', ...corsHeaders });
331→  res.end(JSON.stringify({
332→    error: 'Not Found'
333→  }));
334→}
