337→ * 启动服务器
338→ */
339→function startServer() {
340→  const server = http.createServer(handleRequest);
341→
342→  server.listen(CONFIG.port, '0.0.0.0', () => {
343→    console.log('='.repeat(60));
344→    console.log('🚀 飞书 Webhook 服务器已启动');
345→    console.log('='.repeat(60));
346→    console.log(`📡 监听地址: http://localhost:${CONFIG.port}`);
347→    console.log(`📡 本地IP地址: http://192.168.x.x:${CONFIG.port}`);
348→    console.log();
349→    console.log('📋 API 端点:');
350→    console.log(`  GET  /health        - 健康检查`);
351→    console.log(`  POST /webhook/feishu - 飞书 webhook 接收`);
352→    console.log(`  POST /api/command   - 通用命令接口`);
353→    console.log();
354→    console.log('💡 飞书配置:');
355→    console.log(`  Webhook URL: http://YOUR_IP:${CONFIG.port}/webhook/feishu`);
356→    console.log('='.repeat(60));
357→    console.log();
358→    console.log('📝 日志文件: ' + LOG_FILE);
359→    console.log('💡 按 Ctrl+C 停止服务器');
360→    console.log();
361→
362→    log(`服务器启动成功，监听端口 ${CONFIG.port}`, 'INFO');
363→  });
364→
365→  server.on('error', (error) => {
366→    if (error.code === 'EADDRINUSE') {
367→      console.error(`❌ 端口 ${CONFIG.port} 已被占用`);
368→      console.log('💡 尝试其他端口或关闭占用该端口的程序');
369→    } else {
370→      console.error('❌ 服务器错误:', error.message);
371→    }
372→    process.exit(1);
373→  });
374→
375→  // 优雅退出
376→  process.on('SIGINT', () => {
377→    console.log('\n');
378→    console.log('='.repeat(60));
379→    console.log('👋 正在关闭服务器...');
380→    console.log('='.repeat(60));
381→    server.close(() => {
382→      log('服务器已关闭', 'INFO');
383→      process.exit(0);
384→    });
385→  });
386→}
387→
388→// 启动服务器
389→if (require.main === module) {
390→  startServer();
391→}
392→
393→module.exports = { handleFeishuMessage, executeCommand, startServer };
