 22→// --- Sender name resolution (so the agent can distinguish who is speaking in group chats) ---
 23→// Cache display names by open_id to avoid an API call on every message.
 24→const SENDER_NAME_TTL_MS = 10 * 60 * 1000;
 25→const senderNameCache = new Map<string, { name: string; expireAt: number }>();
 26→
 27→async function resolveFeishuSenderName(params: {
 28→  feishuCfg?: FeishuConfig;
 29→  senderOpenId: string;
 30→  log: (...args: any[]) => void;
 31→}): Promise<string | undefined> {
 32→  const { feishuCfg, senderOpenId, log } = params;
 33→  if (!feishuCfg) return undefined;
 34→  if (!senderOpenId) return undefined;
 35→
 36→  const cached = senderNameCache.get(senderOpenId);
 37→  const now = Date.now();
 38→  if (cached && cached.expireAt > now) return cached.name;
 39→
 40→  try {
 41→    const client = createFeishuClient(feishuCfg);
 42→
 43→    // contact/v3/users/:user_id?user_id_type=open_id
 44→    const res: any = await client.contact.user.get({
 45→      path: { user_id: senderOpenId },
 46→      params: { user_id_type: "open_id" },
 47→    });
 48→
 49→    const name: string | undefined =
 50→      res?.data?.user?.name ||
 51→      res?.data?.user?.display_name ||
 52→      res?.data?.user?.nickname ||
 53→      res?.data?.user?.en_name;
 54→
 55→    if (name && typeof name === "string") {
 56→      senderNameCache.set(senderOpenId, { name, expireAt: now + SENDER_NAME_TTL_MS });
 57→      return name;
 58→    }
 59→
 60→    return undefined;
 61→  } catch (err) {
 62→    // Best-effort. Don't fail message handling if name lookup fails.
 63→    log(`feishu: failed to resolve sender name for ${senderOpenId}: ${String(err)}`);
 64→    return undefined;
 65→  }
 66→}
