110→function parseMessageContent(content: string, messageType: string): string {
111→  try {
112→    const parsed = JSON.parse(content);
113→    if (messageType === "text") {
114→      return parsed.text || "";
115→    }
116→    if (messageType === "post") {
117→      // Extract text content from rich text post
118→      const { textContent } = parsePostContent(content);
119→      return textContent;
120→    }
121→    return content;
122→  } catch {
123→    return content;
124→  }
125→}
126→
127→function checkBotMentioned(event: FeishuMessageEvent, botOpenId?: string): boolean {
128→  const mentions = event.message.mentions ?? [];
129→  if (mentions.length === 0) return false;
130→  if (!botOpenId) return mentions.length > 0;
131→  return mentions.some((m) => m.id.open_id === botOpenId);
132→}
133→
134→function stripBotMention(text: string, mentions?: FeishuMessageEvent["message"]["mentions"]): string {
135→  if (!mentions || mentions.length === 0) return text;
136→  let result = text;
137→  for (const mention of mentions) {
138→    result = result.replace(new RegExp(`@${mention.name}\\s*`, "g"), "").trim();
139→    result = result.replace(new RegExp(mention.key, "g"), "").trim();
140→  }
141→  return result;
142→}
143→
144→/**
145→ * Parse media keys from message content based on message type.
146→ */
147→function parseMediaKeys(
148→  content: string,
149→  messageType: string,
150→): {
151→  imageKey?: string;
152→  fileKey?: string;
153→  fileName?: string;
154→} {
155→  try {
156→    const parsed = JSON.parse(content);
157→    switch (messageType) {
158→      case "image":
159→        return { imageKey: parsed.image_key };
160→      case "file":
161→        return { fileKey: parsed.file_key, fileName: parsed.file_name };
162→      case "audio":
163→        return { fileKey: parsed.file_key };
164→      case "video":
165→        // Video has both file_key (video) and image_key (thumbnail)
166→        return { fileKey: parsed.file_key, imageKey: parsed.image_key };
167→      case "sticker":
168→        return { fileKey: parsed.file_key };
169→      default:
170→        return {};
171→    }
172→  } catch {
173→    return {};
174→  }
175→}
176→
177→/**
178→ * Parse post (rich text) content and extract embedded image keys.
179→ * Post structure: { title?: string, content: [[{ tag, text?, image_key?, ... }]] }
180→ */
181→function parsePostContent(content: string): {
182→  textContent: string;
183→  imageKeys: string[];
184→} {
185→  try {
186→    const parsed = JSON.parse(content);
187→    const title = parsed.title || "";
188→    const contentBlocks = parsed.content || [];
189→    let textContent = title ? `${title}\n\n` : "";
190→    const imageKeys: string[] = [];
191→
192→    for (const paragraph of contentBlocks) {
193→      if (Array.isArray(paragraph)) {
194→        for (const element of paragraph) {
195→          if (element.tag === "text") {
196→            textContent += element.text || "";
197→          } else if (element.tag === "a") {
198→            // Link: show text or href
199→            textContent += element.text || element.href || "";
200→          } else if (element.tag === "at") {
201→            // Mention: @username
202→            textContent += `@${element.user_name || element.user_id || ""}`;
203→          } else if (element.tag === "img" && element.image_key) {
204→            // Embedded image
205→            imageKeys.push(element.image_key);
206→          }
207→        }
208→        textContent += "\n";
209→      }
210→    }
211→
212→    return {
213→      textContent: textContent.trim() || "[富文本消息]",
214→      imageKeys,
215→    };
216→  } catch {
217→    return { textContent: "[富文本消息]", imageKeys: [] };
218→  }
219→}
220→
221→/**
222→ * Infer placeholder text based on message type.
223→ */
224→function inferPlaceholder(messageType: string): string {
225→  switch (messageType) {
226→    case "image":
227→      return "<media:image>";
228→    case "file":
229→      return "<media:document>";
230→    case "audio":
231→      return "<media:audio>";
232→    case "video":
233→      return "<media:video>";
234→    case "sticker":
235→      return "<media:sticker>";
236→    default:
237→      return "<media:document>";
238→  }
239→}
240→
241→/**
242→ * Resolve media from a Feishu message, downloading and saving to disk.
243→ * Similar to Discord's resolveMediaList().
244→ */
245→async function resolveFeishuMediaList(params: {
246→  cfg: ClawdbotConfig;
247→  messageId: string;
248→  messageType: string;
249→  content: string;
250→  maxBytes: number;
251→  log?: (msg: string) => void;
252→}): Promise<FeishuMediaInfo[]> {
253→  const { cfg, messageId, messageType, content, maxBytes, log } = params;
254→
255→  // Only process media message types (including post for embedded images)
256→  const mediaTypes = ["image", "file", "audio", "video", "sticker", "post"];
257→  if (!mediaTypes.includes(messageType)) {
258→    return [];
259→  }
260→
261→  const out: FeishuMediaInfo[] = [];
262→  const core = getFeishuRuntime();
263→
264→  // Handle post (rich text) messages with embedded images
265→  if (messageType === "post") {
266→    const { imageKeys } = parsePostContent(content);
267→    if (imageKeys.length === 0) {
268→      return [];
269→    }
270→
271→    log?.(`feishu: post message contains ${imageKeys.length} embedded image(s)`);
272→
273→    for (const imageKey of imageKeys) {
274→      try {
275→        // Embedded images in post use messageResource API with image_key as file_key
276→        const result = await downloadMessageResourceFeishu({
277→          cfg,
278→          messageId,
279→          fileKey: imageKey,
280→          type: "image",
281→        });
282→
283→        let contentType = result.contentType;
284→        if (!contentType) {
285→          contentType = await core.media.detectMime({ buffer: result.buffer });
286→        }
287→
288→        const saved = await core.channel.media.saveMediaBuffer(
289→          result.buffer,
290→          contentType,
291→          "inbound",
292→          maxBytes,
293→        );
294→
295→        out.push({
296→          path: saved.path,
297→          contentType: saved.contentType,
298→          placeholder: "<media:image>",
299→        });
300→
301→        log?.(`feishu: downloaded embedded image ${imageKey}, saved to ${saved.path}`);
302→      } catch (err) {
303→        log?.(`feishu: failed to download embedded image ${imageKey}: ${String(err)}`);
304→      }
305→    }
306→
307→    return out;
308→  }
309→
310→  // Handle other media types
311→  const mediaKeys = parseMediaKeys(content, messageType);
312→  if (!mediaKeys.imageKey && !mediaKeys.fileKey) {
313→    return [];
314→  }
315→
316→  try {
317→    let buffer: Buffer;
318→    let contentType: string | undefined;
319→    let fileName: string | undefined;
320→
321→    // For message media, always use messageResource API
322→    // The image.get API is only for images uploaded via im/v1/images, not for message attachments
323→    const fileKey = mediaKeys.imageKey || mediaKeys.fileKey;
324→    if (!fileKey) {
325→      return [];
326→    }
327→
328→    const resourceType = messageType === "image" ? "image" : "file";
329→    const result = await downloadMessageResourceFeishu({
330→      cfg,
331→      messageId,
332→      fileKey,
333→      type: resourceType,
334→    });
335→    buffer = result.buffer;
336→    contentType = result.contentType;
337→    fileName = result.fileName || mediaKeys.fileName;
338→
339→    // Detect mime type if not provided
340→    if (!contentType) {
341→      contentType = await core.media.detectMime({ buffer });
342→    }
343→
344→    // Save to disk using core's saveMediaBuffer
345→    const saved = await core.channel.media.saveMediaBuffer(
346→      buffer,
347→      contentType,
348→      "inbound",
349→      maxBytes,
350→      fileName,
351→    );
352→
353→    out.push({
354→      path: saved.path,
355→      contentType: saved.contentType,
356→      placeholder: inferPlaceholder(messageType),
357→    });
358→
359→    log?.(`feishu: downloaded ${messageType} media, saved to ${saved.path}`);
360→  } catch (err) {
361→    log?.(`feishu: failed to download ${messageType} media: ${String(err)}`);
362→  }
363→
364→  return out;
365→}
366→
367→/**
368→ * Build media payload for inbound context.
369→ * Similar to Discord's buildDiscordMediaPayload().
370→ */
371→function buildFeishuMediaPayload(
372→  mediaList: FeishuMediaInfo[],
373→): {
374→  MediaPath?: string;
375→  MediaType?: string;
376→  MediaUrl?: string;
377→  MediaPaths?: string[];
378→  MediaUrls?: string[];
379→  MediaTypes?: string[];
380→} {
381→  const first = mediaList[0];
382→  const mediaPaths = mediaList.map((media) => media.path);
383→  const mediaTypes = mediaList.map((media) => media.contentType).filter(Boolean) as string[];
384→  return {
385→    MediaPath: first?.path,
386→    MediaType: first?.contentType,
387→    MediaUrl: first?.path,
388→    MediaPaths: mediaPaths.length > 0 ? mediaPaths : undefined,
389→    MediaUrls: mediaPaths.length > 0 ? mediaPaths : undefined,
390→    MediaTypes: mediaTypes.length > 0 ? mediaTypes : undefined,
391→  };
392→}
