 28→export async function monitorFeishuProvider(opts: MonitorFeishuOpts = {}): Promise<void> {
 29→  const cfg = opts.config;
 30→  if (!cfg) {
 31→    throw new Error("Config is required for Feishu monitor");
 32→  }
 33→
 34→  const feishuCfg = cfg.channels?.feishu as FeishuConfig | undefined;
 35→  const creds = resolveFeishuCredentials(feishuCfg);
 36→  if (!creds) {
 37→    throw new Error("Feishu credentials not configured (appId, appSecret required)");
 38→  }
 39→
 40→  const log = opts.runtime?.log ?? console.log;
 41→  const error = opts.runtime?.error ?? console.error;
 42→
 43→  if (feishuCfg) {
 44→    botOpenId = await fetchBotOpenId(feishuCfg);
 45→    log(`feishu: bot open_id resolved: ${botOpenId ?? "unknown"}`);
 46→  }
 47→
 48→  const connectionMode = feishuCfg?.connectionMode ?? "websocket";
 49→
 50→  if (connectionMode === "websocket") {
 51→    return monitorWebSocket({ cfg, feishuCfg: feishuCfg!, runtime: opts.runtime, abortSignal: opts.abortSignal });
 52→  }
 53→
 54→  log("feishu: webhook mode not implemented in monitor, use HTTP server directly");
 55→}
