 17→/**
 18→ * Get a message by its ID.
 19→ * Useful for fetching quoted/replied message content.
 20→ */
 21→export async function getMessageFeishu(params: {
 22→  cfg: ClawdbotConfig;
 23→  messageId: string;
 24→}): Promise<FeishuMessageInfo | null> {
 25→  const { cfg, messageId } = params;
 26→  const feishuCfg = cfg.channels?.feishu as FeishuConfig | undefined;
 27→  if (!feishuCfg) {
 28→    throw new Error("Feishu channel not configured");
 29→  }
 30→
 31→  const client = createFeishuClient(feishuCfg);
 32→
 33→  try {
 34→    const response = (await client.im.message.get({
 35→      path: { message_id: messageId },
 36→    })) as {
 37→      code?: number;
 38→      msg?: string;
 39→      data?: {
 40→        items?: Array<{
 41→          message_id?: string;
 42→          chat_id?: string;
 43→          msg_type?: string;
 44→          body?: { content?: string };
 45→          sender?: {
 46→            id?: string;
 47→            id_type?: string;
 48→            sender_type?: string;
 49→          };
 50→          create_time?: string;
 51→        }>;
 52→      };
 53→    };
 54→
 55→    if (response.code !== 0) {
 56→      return null;
 57→    }
 58→
 59→    const item = response.data?.items?.[0];
 60→    if (!item) {
 61→      return null;
 62→    }
 63→
 64→    // Parse content based on message type
 65→    let content = item.body?.content ?? "";
 66→    try {
 67→      const parsed = JSON.parse(content);
 68→      if (item.msg_type === "text" && parsed.text) {
 69→        content = parsed.text;
 70→      }
 71→    } catch {
 72→      // Keep raw content if parsing fails
 73→    }
 74→
 75→    return {
 76→      messageId: item.message_id ?? messageId,
 77→      chatId: item.chat_id ?? "",
 78→      senderId: item.sender?.id,
 79→      senderOpenId: item.sender?.id_type === "open_id" ? item.sender?.id : undefined,
 80→      content,
 81→      contentType: item.msg_type ?? "text",
 82→      createTime: item.create_time ? parseInt(item.create_time, 10) : undefined,
 83→    };
 84→  } catch {
 85→    return null;
 86→  }
 87→}
