 18→/**
 19→ * Detect if text contains markdown elements that benefit from card rendering.
 20→ * Used by auto render mode.
 21→ */
 22→function shouldUseCard(text: string): boolean {
 23→  // Code blocks (fenced)
 24→  if (/```[\s\S]*?```/.test(text)) return true;
 25→  // Tables (at least header + separator row with |)
 26→  if (/\|.+\|[\r\n]+\|[-:| ]+\|/.test(text)) return true;
 27→  return false;
 28→}
