23→  const feishuCfg = cfg.channels?.feishu as FeishuConfig | undefined;
24→  if (!feishuCfg) {
25→    return { messageId, reactionId: null };
26→  }
27→
28→  const client = createFeishuClient(feishuCfg);
29→
30→  try {
31→    const response = await client.im.messageReaction.create({
32→      path: { message_id: messageId },
33→      data: {
34→        reaction_type: { emoji_type: TYPING_EMOJI },
35→      },
36→    });
37→
38→    const reactionId = (response as any)?.data?.reaction_id ?? null;
39→    return { messageId, reactionId };
40→  } catch (err) {
41→    // Silently fail - typing indicator is not critical
42→    console.log(`[feishu] failed to add typing indicator: ${err}`);
43→    return { messageId, reactionId: null };
44→  }
45→}
46→
47→/**
48→ * Remove a typing indicator (reaction) from a message
49→ */
50→export async function removeTypingIndicator(params: {
51→  cfg: ClawdbotConfig;
52→  state: TypingIndicatorState;
53→}): Promise<void> {
54→  const { cfg, state } = params;
55→  if (!state.reactionId) return;
56→
57→  const feishuCfg = cfg.channels?.feishu as FeishuConfig | undefined;
58→  if (!feishuCfg) return;
59→
60→  const client = createFeishuClient(feishuCfg);
61→
62→  try {
63→    await client.im.messageReaction.delete({
64→      path: {
65→        message_id: state.messageId,
66→        reaction_id: state.reactionId,
67→      },
68→    });
69→  } catch (err) {
70→    // Silently fail - cleanup is not critical
71→    console.log(`[feishu] failed to remove typing indicator: ${err}`);
72→  }
73→}
