 1→import type { ClawdbotConfig } from "clawdbot/plugin-sdk";
 2→import { DEFAULT_ACCOUNT_ID } from "clawdbot/plugin-sdk";
 3→import type { FeishuConfig, FeishuDomain, ResolvedFeishuAccount } from "./types.js";
 4→
 5→export function resolveFeishuCredentials(cfg?: FeishuConfig): {
 6→  appId: string;
 7→  appSecret: string;
 8→  encryptKey?: string;
 9→  verificationToken?: string;
10→  domain: FeishuDomain;
11→} | null {
12→  const appId = cfg?.appId?.trim();
13→  const appSecret = cfg?.appSecret?.trim();
14→  if (!appId || !appSecret) return null;
15→  return {
16→    appId,
17→    appSecret,
18→    encryptKey: cfg?.encryptKey?.trim() || undefined,
19→    verificationToken: cfg?.verificationToken?.trim() || undefined,
20→    domain: cfg?.domain ?? "feishu",
21→  };
22→}
23→
24→export function resolveFeishuAccount(params: {
25→  cfg: ClawdbotConfig;
26→  accountId?: string | null;
27→}): ResolvedFeishuAccount {
28→  const feishuCfg = params.cfg.channels?.feishu as FeishuConfig | undefined;
29→  const enabled = feishuCfg?.enabled !== false;
30→  const creds = resolveFeishuCredentials(feishuCfg);
31→
32→  return {
33→    accountId: params.accountId?.trim() || DEFAULT_ACCOUNT_ID,
34→    enabled,
35→    configured: Boolean(creds),
36→    appId: creds?.appId,
37→    domain: creds?.domain ?? "feishu",
38→  };
39→}
40→
41→export function listFeishuAccountIds(_cfg: ClawdbotConfig): string[] {
42→  return [DEFAULT_ACCOUNT_ID];
43→}
44→
45→export function resolveDefaultFeishuAccountId(_cfg: ClawdbotConfig): string {
46→  return DEFAULT_ACCOUNT_ID;
47→}
48→
49→export function listEnabledFeishuAccounts(cfg: ClawdbotConfig): ResolvedFeishuAccount[] {
50→  return listFeishuAccountIds(cfg)
51→    .map((accountId) => resolveFeishuAccount({ cfg, accountId }))
52→    .filter((account) => account.enabled && account.configured);
53→}
