 1→import type { FeishuConfig, FeishuProbeResult } from "./types.js";
 2→import { createFeishuClient } from "./client.js";
 3→import { resolveFeishuCredentials } from "./accounts.js";
 4→
 5→export async function probeFeishu(cfg?: FeishuConfig): Promise<FeishuProbeResult> {
 6→  const creds = resolveFeishuCredentials(cfg);
 7→  if (!creds) {
 8→    return {
 9→      ok: false,
10→      error: "missing credentials (appId, appSecret)",
11→    };
12→  }
13→
14→  try {
15→    const client = createFeishuClient(cfg!);
16→    // Use im.chat.list as a simple connectivity test
17→    // The bot info API path varies by SDK version
18→    const response = await (client as any).request({
19→      method: "GET",
20→      url: "/open-apis/bot/v3/info",
21→      data: {},
22→    });
23→
24→    if (response.code !== 0) {
25→      return {
26→        ok: false,
27→        appId: creds.appId,
28→        error: `API error: ${response.msg || `code ${response.code}`}`,
29→      };
30→    }
31→
32→    const bot = response.bot || response.data?.bot;
33→    return {
34→      ok: true,
35→      appId: creds.appId,
36→      botName: bot?.bot_name,
37→      botOpenId: bot?.open_id,
38→    };
39→  } catch (err) {
40→    return {
41→      ok: false,
42→      appId: creds.appId,
43→      error: err instanceof Error ? err.message : String(err),
44→    };
45→  }
46→}
